import{c as r,Q as e,j as l,m as a}from"./chunks/framework.BIBjCrbN.js";const d=JSON.parse('{"title":"华中科技大学","description":"华中科技大学生物医学工程/超声成像博士项目指南 — 超声断层成像、医学影像AI方向","frontmatter":{"title":"华中科技大学","description":"华中科技大学生物医学工程/超声成像博士项目指南 — 超声断层成像、医学影像AI方向","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["bme","medical-physics"],"tags":["华中科技大学","武汉",985],"admission-year":2027},"headers":[],"relativePath":"universities/hust.md","filePath":"universities/hust.md","lastUpdated":1780110618000}'),i={name:"universities/hust.md"};function n(o,t,s,h,u,g){return e(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="华中科技大学" tabindex="-1">华中科技大学 <a class="header-anchor" href="#华中科技大学" aria-label="Permalink to &quot;华中科技大学&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日</p></blockquote><h2 id="学校概况" tabindex="-1">学校概况 <a class="header-anchor" href="#学校概况" aria-label="Permalink to &quot;学校概况&quot;">​</a></h2><p>华中科技大学生物医学工程为国家一级重点学科，在<strong>超声断层成像（UCT）<strong>和</strong>医学图像AI分析</strong>方向国内领先。丁明跃团队研发的乳腺超声CT系统获国内首个超声断层成像医疗器械注册证。</p><p><strong>官方链接</strong>:</p><ul><li>学校官网: <a href="https://www.hust.edu.cn" target="_blank" rel="noreferrer">https://www.hust.edu.cn</a></li><li>研究生院: <a href="http://gs.hust.edu.cn" target="_blank" rel="noreferrer">http://gs.hust.edu.cn</a></li><li>生命科学与技术学院: <a href="http://life.hust.edu.cn" target="_blank" rel="noreferrer">http://life.hust.edu.cn</a></li></ul><hr><h2 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h2><h3 id="——-医学影像-超声方向-——" tabindex="-1">—— 医学影像 / 超声方向 —— <a class="header-anchor" href="#——-医学影像-超声方向-——" aria-label="Permalink to &quot;—— 医学影像 / 超声方向 ——&quot;">​</a></h3><h4 id="丁明跃-—-教授、博导" tabindex="-1">丁明跃 — 教授、博导 <a class="header-anchor" href="#丁明跃-—-教授、博导" aria-label="Permalink to &quot;丁明跃 — 教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 生命科学与技术学院（曾任系主任、院长助理）</li><li><strong>个人主页</strong>: <a href="http://faculty.hust.edu.cn/MINGYUEDING/" target="_blank" rel="noreferrer">http://faculty.hust.edu.cn/MINGYUEDING/</a></li><li><strong>荣誉</strong>: IEEE高级会员、湖北省生物医学工程学会副会长</li></ul><p><strong>研究方向</strong>:</p><ul><li>医学图像处理与超声影像</li><li>颈动脉三维超声成像</li><li><strong>超声断层成像</strong>（乳腺癌早期诊断与筛查）</li><li>肌骨成像</li></ul><p><strong>核心成果</strong>:</p><ul><li>🏆 <strong>2025年</strong>团队自主研发的&quot;乳腺超声计算机断层成像系统&quot;获<strong>国内首个超声断层成像医疗器械注册证</strong></li><li>全球首台肌骨超声断层成像系统于2023年完成临床研究</li><li>获国内外专利40余项，专利转化金额1300万元</li><li>湖北省科技进步二等奖、华中科技大学教学名师</li></ul><hr><h4 id="尉迟明-—-教授、博导" tabindex="-1">尉迟明 — 教授、博导 <a class="header-anchor" href="#尉迟明-—-教授、博导" aria-label="Permalink to &quot;尉迟明 — 教授、博导&quot;">​</a></h4><ul><li><strong>学院</strong>: 生命科学与技术学院（生物医学工程系副系主任）</li><li><strong>个人主页</strong>: <a href="http://faculty.hust.edu.cn/yuchiming/" target="_blank" rel="noreferrer">http://faculty.hust.edu.cn/yuchiming/</a></li><li><strong>邮箱</strong>: <a href="mailto:m.yuchi@hust.edu.cn" target="_blank" rel="noreferrer">m.yuchi@hust.edu.cn</a></li><li><strong>荣誉</strong>: 万人计划科技创业领军人才</li></ul><p><strong>研究方向</strong>:</p><ul><li><strong>超声断层成像技术</strong>（超声CT）</li><li>乳腺癌与肌骨超声检测</li></ul><p><strong>核心成果</strong>: 研制出国内首台具有自主知识产权的超声CT系统</p><hr><h4 id="邱武-—-教授-国家高层次青年人才" tabindex="-1">邱武 — 教授（国家高层次青年人才） <a class="header-anchor" href="#邱武-—-教授-国家高层次青年人才" aria-label="Permalink to &quot;邱武 — 教授（国家高层次青年人才）&quot;">​</a></h4><ul><li><strong>学院</strong>: 生命科学与技术学院</li><li><strong>邮箱</strong>: <a href="mailto:wuqiu@hust.edu.cn" target="_blank" rel="noreferrer">wuqiu@hust.edu.cn</a></li><li><strong>荣誉</strong>: 湖北省政府特殊津贴专家</li></ul><p><strong>研究方向</strong>:</p><ul><li>AI在医学影像分析中的应用</li><li>急性期脑卒中影像学诊断</li><li>三维超声断层成像（UCT）</li><li>多模影像导引前列腺穿刺与治疗</li></ul><hr><h2 id="_2026年博士招生-参考" tabindex="-1">2026年博士招生（参考） <a class="header-anchor" href="#_2026年博士招生-参考" aria-label="Permalink to &quot;2026年博士招生（参考）&quot;">​</a></h2><ul><li>招生方式: 申请考核制</li><li>报名时间: 通常在2025年11月-12月</li><li>事件: 2026年6月12-14日，第五届MUST（Medical Ultrasound Tomography）研讨会在武汉召开</li></ul><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>超声方向高度匹配</strong>：UCL医用物理本科 + HIFU超声系统RA经验 + 超声成像课程基础 — 叙事线完整</li><li><strong>丁明跃/尉迟明团队</strong>：超声断层成像前沿，工程化程度高，适合你的BME工程背景</li><li><strong>邱武团队</strong>：AI+医学影像，你的Python/MATLAB编程能力直接可用</li><li><strong>硬件+算法双背景是优势</strong>：大多数申请人只有单方面背景</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="http://faculty.hust.edu.cn/MINGYUEDING/" target="_blank" rel="noreferrer">丁明跃主页</a>（访问日期: 2026-05-25）</li><li><a href="http://faculty.hust.edu.cn/yuchiming/" target="_blank" rel="noreferrer">尉迟明主页</a>（访问日期: 2026-05-25）</li><li><a href="https://www.must-hust-wuhan.com/" target="_blank" rel="noreferrer">MUST研讨会</a>（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以华中科技大学研究生院官网最新公告为准。</em></p>',37)])])}const f=r(i,[["render",n]]);export{d as __pageData,f as default};
